create or replace semantic view QUERY_OPTIMIZATION_DB.AGENT.QUERY_PERFORMANCE
	tables (
		QUERY_OPTIMIZATION_DB.AGENT.BAD_QUERIES_RAW_IT primary key (CAPTURE_ID) unique (CAPTURE_ID,QUERY_ID) comment='The table contains records of database queries flagged for performance or cost concerns. Each record represents a single query execution and includes details about the executing user, role, and application, as well as performance metrics such as elapsed time, data scanned, cache usage, and associated compute costs.',
		QUERY_OPTIMIZATION_DB.AGENT.QUERY_ANALYSIS_RESULTS_IT primary key (CAPTURE_ID) unique (CAPTURE_ID,QUERY_ID) comment='The table contains records of query analysis results produced by an automated agent. Each record captures key findings, optimization suggestions, and proposed query rewrites associated with a specific query at a given point in time.'
	)
	relationships (
