		BAD_QUERIES_RAW_IT.QUERY_TYPE as QUERY_TYPE comment='The type of SQL query that was executed.',
		BAD_QUERIES_RAW_IT.QUEUE_STATUS as QUEUE_STATUS comment='The queuing status of a query at the time it was captured.',
		BAD_QUERIES_RAW_IT.ROLE_NAME as ROLE_NAME comment='The name of the role associated with the query execution.',
		BAD_QUERIES_RAW_IT.SPILL_STATUS as SPILL_STATUS comment='The spill status of a query indicating whether data spilled to disk during execution.',
		BAD_QUERIES_RAW_IT.USER_NAME as USER_NAME comment='The name of the user who executed the query.',
		BAD_QUERIES_RAW_IT.WAREHOUSE_NAME as WAREHOUSE_NAME comment='The name of the warehouse associated with the query.',
		BAD_QUERIES_RAW_IT.WAREHOUSE_SIZE as WAREHOUSE_SIZE comment='The size of the virtual warehouse used to execute the query.',
		BAD_QUERIES_RAW_IT.CAPTURE_TIMESTAMP as CAPTURE_TIMESTAMP comment='The timestamp indicating when the query data was captured.',
		BAD_QUERIES_RAW_IT.QUERY_DATE as QUERY_DATE comment='The date on which the query was executed.',
		QUERY_ANALYSIS_RESULTS_IT.ANALYSIS_ID as ANALYSIS_ID comment='Unique identifier for each query analysis result record.',
		QUERY_ANALYSIS_RESULTS_IT.CAPTURE_ID as CAPTURE_ID comment='Identifier linking query analysis results to a specific data capture event.',
