	with extension (CA='{"tables":[{"name":"BAD_QUERIES_RAW_IT","dimensions":[{"name":"ANTI_PATTERN_REASON","sample_values":["[\\n  {\\n    \\"analysis\\": \\"SELECT * is not recommended as it can lead to unnecessary data transfer and slow query performance. Consider selecting only the necessary columns.\\",\\n    \\"analysis_number\\": 1\\n  },\\n  {\\n    \\"analysis\\": \\"The table name ''QUERY_OPTIMIZATION_DB.AGENT.QUERY_ANALYSIS_RESULTS_IT'' is not qualified with a schema name. This can lead to ambiguity and potential performance issues. Consider qualifying the table name with the schema name.\\",\\n    \\"analysis_number\\": 2\\n  }\\n]","[\\n  {\\n    \\"analysis\\": \\"SELECT * is not used, but could be optimized by selecting only necessary columns\\",\\n    \\"analysis_number\\": 1\\n  },\\n  {\\n    \\"analysis\\": \\"The GROUP BY clause is not sargable, consider using a more efficient grouping key\\",\\n    \\"analysis_number\\": 2\\n  }\\n]","[\\n  {\\n    \\"analysis\\": \\"SELECT * usage\\",\\n    \\"analysis_number\\": 1\\n  }\\n]"]},{"name":"CAPTURE_ID","sample_values":["103","101","17"]},{"name":"CLIENT_APPLICATION_ID","sample_values":["Snowsight "]},{"name":"CLIENT_SOURCE","sample_values":["Snowsight "]},{"name":"EXECUTION_STATUS","sample_values":["SUCCESS","FAIL"]},{"name":"HAS_ANTI_PATTERN","sample_values":["TRUE"]},{"name":"IS_ANALYZED","sample_values":["FALSE","TRUE"]},{"name":"QUERY_ID","sample_values":["01c317a9-0001-a03e-0002-724e001d11c2","01c30bfb-0001-9dd9-0002-724e00199466","01c30176-0001-9bda-0002-724e0016013a"]},{"name":"QUERY_TEXT","sample_values":["WITH QUERY_COST_BASE AS (\\n    SELECT\\n        qh.QUERY_ID,\\n        qh.WAREHOUSE_NAME,\\n        qh.WAREHOUSE_SIZE,\\n        qh.USER_NAME,\\n        qh.ROLE_NAME,\\n        qh.QUERY_TYPE,\\n        qh.EXECUTION_STATUS,\\n        DATE(qh.START_TIME) AS QUERY_DATE,\\n        qh.TOTAL_ELAPSED_TIME / 1000.0 AS TOTAL_ELAPSED_TIME_SEC,\\n        COALESCE(qa.CREDITS_ATTRIBUTED_COMPUTE, 0) + COALESCE(qa.CREDITS_USED_QUERY_ACCELERATION, 0) AS TOTAL_CREDITS,\\n        ROUND((COALESCE(qa.CREDITS_ATTRIBUTED_COMPUTE, 0) + COALESCE(qa.CREDITS_USED_QUERY_ACCELERATION, 0) + COALESCE(qh.CREDITS_USED_CLOUD_SERVICES, 0)) * 1.83, 4) AS TOTAL_COST_USD,\\n        qh.BYTES_SCANNED / POWER(1024, 3) AS GB_SCANNED,\\n        qh.PERCENTAGE_SCANNED_FROM_CACHE,\\n        CASE WHEN qh.PARTITIONS_TOTAL > 0 THEN ROUND(qh.PARTITIONS_SCANNED * 100.0 / qh.PARTITIONS_TOTAL, 2) ELSE 0 END AS PARTITION_SCAN_PCT,\\n        CASE \\n            WHEN qh.BYTES_SPILLED_TO_REMOTE_STORAGE > 0 THEN ''Remote Spill''\\n            WHEN qh.BYTES_SPILLED_TO_LOCAL_STORAGE > 0 THEN ''Local Spill''\\n            ELSE ''No Spill''\\n        END AS SPILL_STATUS,\\n        CASE\\n            WHEN qh.QUEUED_OVERLOAD_TIME > 0 THEN ''Queued''\\n            ELSE ''Not Queued''\\n        END AS QUEUE_STATUS,\\n        LEFT(qh.QUERY_TEXT, 16000) AS QUERY_TEXT\\n    FROM SNOWFLAKE.ACCOUNT_USAGE.QUERY_HISTORY qh\\n    LEFT JOIN SNOWFLAKE.ACCOUNT_USAGE.QUERY_ATTRIBUTION_HISTORY qa\\n        ON qh.QUERY_ID = qa.QUERY_ID\\n    WHERE qh.START_TIME > DATEADD(DAY, -7, CURRENT_TIMESTAMP())\\n      AND qh.QUERY_TYPE IN (''SELECT'', ''INSERT'', ''UPDATE'', ''DELETE'', ''MERGE'', ''CREATE_TABLE_AS_SELECT'')\\n      AND qh.QUERY_ID NOT IN (SELECT QUERY_ID FROM QUERY_OPTIMIZATION_DB.AGENT.BAD_QUERIES_RAW_IT)\\n),\\nFILTERED_QUERIES AS (\\n    SELECT *\\n    FROM QUERY_COST_BASE\\n    WHERE TOTAL_COST_USD > 0.01\\n       OR TOTAL_ELAPSED_TIME_SEC > 60\\n       OR SPILL_STATUS != ''No Spill''\\n       OR PARTITION_SCAN_PCT > 50\\n    ORDER BY TOTAL_COST_USD DESC\\n    LIMIT 2\\n),\\nSCORED_QUERIES AS (\\n    SELECT \\n        *,\\n        AI_FILTER(\\n            PROMPT(''You are a Snowflake query optimization expert.\\n\\nEvaluate the SQL query below and determine if it contains performance anti-patterns.\\n\\nConsider:\\n1. Data scanning inefficiency (full table scans, high partition scan %)\\n2. Poor filtering (missing or weak WHERE clause)\\n3. SELECT * usage\\n4. Join inefficiencies (CROSS JOIN, missing join conditions)\\n5. Non-sargable predicates (functions on indexed/filter columns)\\n6. Spilling risk patterns (large joins, aggregations without pruning)\\n7. Redundant or repeated subqueries\\n8. Lack of partition pruning\\n\\nReturn:\\nTRUE  -> if query is likely inefficient\\nFALSE -> if query is reasonably optimized\\n\\nBe strict: only return TRUE if there is clear evidence.\\n\\nQuery:\\n{0}'', QUERY_TEXT)\\n        ) AS HAS_ANTI_PATTERN\\n    FROM FILTERED_QUERIES\\n)\\nSELECT \\n    *,\\n    PARSE_JSON(\\n    REPLACE(\\n    AI_COMPLETE(\\n        ''llama3.1-8b'',\\n        CONCAT(''Return ONLY a JSON array Format: [{\\"analysis_number\\":1,\\"analysis\\":\\"desc\\"}] list the performance anti-patterns found in this SQL query (e.g., SELECT *, missing WHERE, CROSS JOIN, non-sargable predicates). No text before or after. SQL: '', QUERY_TEXT)\\n    ), ''\\\\\\\\\\\\\\"'', ''\\\\\\"'') )\\n    AS ANTI_PATTERN_REASON\\nFROM SCORED_QUERIES\\nWHERE HAS_ANTI_PATTERN = TRUE\\nORDER BY TOTAL_COST_USD DESC;","SELECT * FROM QUERY_OPTIMIZATION_DB.AGENT.QUERY_ANALYSIS_RESULTS_IT ;","SELECT\\n    SEQ4() % 10000000 AS group_key,\\n    COUNT(*) AS cnt\\nFROM \\n    TABLE(GENERATOR(ROWCOUNT => 300000000))\\nGROUP BY \\n    SEQ4() % 10000000;"]},{"name":"QUERY_TYPE","sample_values":["SELECT","UPDATE","INSERT"]},{"name":"QUEUE_STATUS","sample_values":["Not Queued"]},{"name":"ROLE_NAME","sample_values":["ACCOUNTADMIN"]},{"name":"SPILL_STATUS","sample_values":["Local Spill","No Spill"]},{"name":"USER_NAME","sample_values":["SYSTEM","SSARKAR"]},{"name":"WAREHOUSE_NAME","sample_values":["COMPUTE_WH"]},{"name":"WAREHOUSE_SIZE","sample_values":["X-Small"]}],"facts":[{"name":"GB_SCANNED","sample_values":["0.2008653134","0.000007629394531","0"]},{"name":"PARTITION_SCAN_PCT","sample_values":["100","0","0.03"]},{"name":"PERCENTAGE_SCANNED_FROM_CACHE","sample_values":["0","0.9943973383","1"]},{"name":"TOTAL_COST_USD","sample_values":["0.013","0.0017","0.0024"]},{"name":"TOTAL_CREDITS","sample_values":["0.001287361111","0.006402902023","0.005603881942"]},{"name":"TOTAL_ELAPSED_TIME_SEC","sample_values":["6.889","0.246","3.42"]}],"time_dimensions":[{"name":"CAPTURE_TIMESTAMP","sample_values":["2026-03-17T21:19:54.080+0000","2026-03-17T22:19:55.041+0000","2026-03-18T03:19:55.089+0000"]},{"name":"QUERY_DATE","sample_values":["2026-03-17","2026-03-15","2026-03-13"]}]},{"name":"QUERY_ANALYSIS_RESULTS_IT","dimensions":[{"name":"ANALYSIS_ID","sample_values":["3","2","1"]},{"name":"CAPTURE_ID","sample_values":["1","3","4"]},{"name":"KEY_FINDINGS","sample_values":[" - Cache Hit: 0%\\n- Partitions Scanned: 0%"," - Low Cache Hit (1%)\\n- No Partitions Scanned (0%)"," - Cache Hit: 1%\\n- Partitions Scanned: 0%"]},{"name":"OPTIMIZATION_SUGGESTIONS","sample_values":["1. **Increase Warehouse Size**: The current warehouse size is X-Small. Increase it to a larger size (e.g., Small or Medium) to provide more compute resources and reduce query execution time.\\n\\n2. **Reduce Data Generation**: The query generates a large amount of data (1 trillion rows). Reduce the ROWCOUNT in the GENERATOR functions to a more manageable number to decrease the data volume and cost.\\n\\n3. **Use Result Caching**: To improve cache hit rate, use the RESULT_SCAN function to cache the query results for subsequent reuse, reducing the need to recompute the data.","1. **Increase Warehouse Size**: The current warehouse size is X-Small. Increasing the warehouse size to Small or Medium can improve query performance by providing more compute resources.\\n\\n2. **Reduce Data Generation**: The query generates a large amount of data using `SEQ4()` and `ARRAY_GENERATE_RANGE()`. If possible, reduce the range or row count to minimize the amount of data processed.\\n\\n3. **Optimize Data Storage**: If the data generated by `SEQ4()` and `ARRAY_GENERATE_RANGE()` is static and reused frequently, consider storing it in a table to leverage caching and reduce computation.","1. **Increase Warehouse Size**: The current warehouse size is X-Small. Increasing the warehouse size to Small or Medium can improve query performance and reduce execution time.\\n\\n2. **Enable Query Acceleration**: Ensure that query acceleration is enabled to leverage caching and reduce the cost of repeated queries. This can be done by setting the `USE_CACHED_RESULT` parameter to `TRUE`.\\n\\n3. **Optimize Query Structure**: Simplify the query by removing unnecessary calculations or columns that are not used in the final result. This can reduce the amount of data processed and improve performance."]},{"name":"QUERY_ID","sample_values":["01c30165-0001-9c47-0002-724e00161072","01c30176-0001-9c5d-0002-724e0015f46e","01c30187-0001-9c5c-0002-724e0015e4ae"]},{"name":"SUGGESTED_QUERY_REWRITE","sample_values":[" ```sql\\nSELECT\\n    SEQ4() AS id1,\\n    SEQ8() AS id2\\nFROM\\n    TABLE(GENERATOR(ROWCOUNT => 1000000)) t1\\nLIMIT 1000000;\\n```"," ```sql\\nWITH base AS (\\n    SELECT\\n        SEQ4() AS seq,\\n        ARRAY_GENERATE_RANGE(1,1000) AS arr\\n    FROM TABLE(GENERATOR(ROWCOUNT => 1000000))\\n)\\n\\nSELECT\\n    b.seq,\\n    f.value\\nFROM\\n    base b\\n    JOIN LATERAL FLATTEN(input => b.arr) f\\nWHERE\\n    b.seq BETWEEN 1 AND 100000\\nLIMIT 100000;\\n```"," ```sql\\nWITH QUERY_COST_BASE AS (\\n    SELECT\\n        qh.QUERY_ID,\\n        qh.WAREHOUSE_NAME,\\n        qh.WAREHOUSE_SIZE,\\n        qh.USER_NAME,\\n        qh.ROLE_NAME,\\n        qh.QUERY_TYPE,\\n        qh.EXECUTION_STATUS,\\n        DATE(qh.START_TIME) AS QUERY_DATE,\\n        qh.TOTAL_ELAPSED_TIME / 1000.0 AS TOTAL_ELAPSED_TIME_SEC,\\n        COALESCE(qa.CREDITS_ATTRIBUTED_COMPUTE, 0) + COALESCE(qa.CREDITS_USED_QUERY_ACCELERATION, 0) AS TOTAL_CREDITS,\\n        ROUND((COALESCE(qa.CREDITS_ATTRIBUTED_COMPUTE, 0) + COALESCE(qa.CREDITS_USED_QUERY_ACCELERATION, 0) + COALESCE(qh.CREDITS_USED_CLOUD_SERVICES, 0)) * 1.83, 4) AS TOTAL_COST_USD,\\n        qh.BYTES_SCANNED / POWER(1024, 3) AS GB_SCANNED,\\n        qh.PERCENTAGE_SCANNED_FROM_CACHE,\\n        CASE WHEN qh.PARTITIONS_TOTAL > 0 THEN ROUND(qh.PARTITIONS_SCANNED * 100.0 / qh.PARTITIONS_TOTAL, 2) ELSE 0 END AS PARTITION_SCAN_PCT,\\n        CASE\\n            WHEN qh.BYTES_SPILLED_TO_REMOTE_STORAGE > 0 THEN ''Remote Spill''\\n            WHEN qh.BYTES_SPILLED_TO_LOCAL_STORAGE > 0 THEN ''Local Spill''\\n            ELSE ''No Spill''\\n        END AS SPILL_STATUS,\\n        CASE\\n            WHEN qh.QUEUED_OVERLOAD_TIME > 0 THEN ''Queued''\\n            ELSE ''Not Queued''\\n        END AS QUEUE_STATUS,\\n        LEFT(qh.QUERY_TEXT, 2000) AS QUERY_TEXT_PREVIEW,\\n        qh.START_TIME\\n    FROM SNOWFLAKE.ACCOUNT_USAGE.QUERY_HISTORY qh\\n    LEFT JOIN SNOWFLAKE.ACCOUNT_USAGE.QUERY_ACCELERATION_HISTORY qa\\n    ON qh.QUERY_ID = qa.QUERY_ID\\n    WHERE qh.START_TIME >= DATEADD(day, -7, CURRENT_DATE)\\n)\\nSELECT *\\nFROM QUERY_COST_BASE\\nLIMIT 10;\\n```"]}],"time_dimensions":[{"name":"ANALYSIS_TIMESTAMP","sample_values":["2026-03-17T21:21:38.213+0000","2026-03-18T06:00:01.784+0000"]}]}],"relationships":[{"name":"QUERY_ANALYSIS_RESULTS_IT_TO_BAD_QUERIES_RAW_IT","relationship_type":"one_to_one","join_type":"inner"}]}');



create or replace semantic view QUERY_OPTIMIZATION_DB.AGENT.QUERY_PERFORMANCE_IT
	tables (
