	)
	relationships (
		BAD_QUERIES_RAW_IT_TO_QUERY_ANALYSIS_RESULTS_IT as BAD_QUERIES_RAW_IT(CAPTURE_ID,QUERY_ID) references QUERY_ANALYSIS_RESULTS_IT(CAPTURE_ID,QUERY_ID)
	)
	facts (
