		BAD_QUERIES_RAW_IT.PARTITION_SCAN_PCT as PARTITION_SCAN_PCT comment='The percentage of partitions scanned during query execution.',
		BAD_QUERIES_RAW_IT.PERCENTAGE_SCANNED_FROM_CACHE as PERCENTAGE_SCANNED_FROM_CACHE comment='The percentage of data scanned from cache during query execution.',
		BAD_QUERIES_RAW_IT.TOTAL_COST_USD as TOTAL_COST_USD comment='The total cost of the query in United States dollars.',
