		QUERY_ANALYSIS_RESULTS_IT.CAPTURE_ID as CAPTURE_ID comment='Unique identifier assigned to each query capture record.',
		QUERY_ANALYSIS_RESULTS_IT.KEY_FINDINGS as KEY_FINDINGS comment='Key findings from query performance analysis, including metrics such as cache hit rates and partition scan percentages.',
		QUERY_ANALYSIS_RESULTS_IT.OPTIMIZATION_SUGGESTIONS as OPTIMIZATION_SUGGESTIONS comment='Optimization suggestions and recommended actions for improving query performance.',
		QUERY_ANALYSIS_RESULTS_IT.QUERY_ID as QUERY_ID comment='Unique identifier assigned to each query.',
		QUERY_ANALYSIS_RESULTS_IT.SUGGESTED_QUERY_REWRITE as SUGGESTED_QUERY_REWRITE comment='Suggested rewrites or optimizations of SQL queries generated by an agent to improve query performance.',
		QUERY_ANALYSIS_RESULTS_IT.ANALYSIS_TIMESTAMP as ANALYSIS_TIMESTAMP comment='The date and time at which the query analysis was performed.'
